logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("screenshot_service")

APP_HOST = os.getenv("APP_HOST", "0.0.0.0")
APP_PORT = int(os.getenv("APP_PORT", "8080"))
AWS_REGION = os.getenv("AWS_REGION", "us-east-1")
S3_BUCKET = os.getenv("S3_BUCKET", "")
S3_PREFIX = os.getenv("S3_PREFIX", "screenshots")
PUBLIC_BASE_URL = os.getenv("PUBLIC_BASE_URL", "")
USE_PRESIGNED_URLS = os.getenv("USE_PRESIGNED_URLS", "true").lower() == "true"

CHROME_BIN = os.getenv("CHROME_BIN", "/usr/bin/google-chrome")
CHROMEDRIVER_BIN = os.getenv("CHROMEDRIVER_BIN", "/usr/local/bin/chromedriver")
PHANTOMJS_BIN = os.getenv("PHANTOMJS_BIN", "/usr/local/bin/phantomjs")
BROWSER_ENGINE = os.getenv("BROWSER_ENGINE", "chrome").lower()

SCREENSHOT_WIDTH = int(os.getenv("SCREENSHOT_WIDTH", "1280"))
SCREENSHOT_HEIGHT = int(os.getenv("SCREENSHOT_HEIGHT", "720"))
THUMBNAIL_WIDTH = int(os.getenv("THUMBNAIL_WIDTH", "600"))
THUMBNAIL_HEIGHT = int(os.getenv("THUMBNAIL_HEIGHT", "315"))
PAGE_LOAD_TIMEOUT = int(os.getenv("PAGE_LOAD_TIMEOUT", "25"))
IMPLICIT_WAIT = int(os.getenv("IMPLICIT_WAIT", "2"))

MAX_URL_LENGTH = int(os.getenv("MAX_URL_LENGTH", "2048"))
ALLOW_PRIVATE_IPS = os.getenv("ALLOW_PRIVATE_IPS", "false").lower() == "true"

app = Flask(__name__)
s3 = boto3.client("s3", region_name=AWS_REGION)


def normalize_url(url: str) -> str:
    url = (url or "").strip()
    if not url:
        raise ValueError("URL is required")
    if len(url) > MAX_URL_LENGTH:
        raise ValueError("URL too long")
    if not re.match(r"^https?://", url, re.IGNORECASE):
        url = "https://" + url
    parsed = urlparse(url)
    if parsed.scheme not in ("http", "https"):
        raise ValueError("Only http/https URLs are allowed")
    if not parsed.netloc:
        raise ValueError("Invalid URL")
    return url


def is_private_hostname(hostname: str) -> bool:
    import socket
    import ipaddress
    try:
        infos = socket.getaddrinfo(hostname, None)
        for info in infos:
            ip = info[4][0]
            addr = ipaddress.ip_address(ip)
            if addr.is_private or addr.is_loopback or addr.is_link_local or addr.is_reserved or addr.is_multicast:
                return True
    except Exception:
        return True
    return False


def validate_url(url: str) -> str:
    normalized = normalize_url(url)
    parsed = urlparse(normalized)
    if not ALLOW_PRIVATE_IPS and is_private_hostname(parsed.hostname or ""):
        raise ValueError("Private/internal addresses are not allowed")
    return normalized


def make_key(url: str) -> str:
    digest = hashlib.sha256(url.encode("utf-8")).hexdigest()
    return f"{S3_PREFIX}/{digest[:2]}/{digest}.jpg"


def s3_url_for_key(key: str) -> str:
    if PUBLIC_BASE_URL:
        return f"{PUBLIC_BASE_URL.rstrip('/')}/{key}"
    if USE_PRESIGNED_URLS:
        return s3.generate_presigned_url(
            "get_object",
            Params={"Bucket": S3_BUCKET, "Key": key},
            ExpiresIn=86400,
        )
    return f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{key}"


def object_exists(bucket: str, key: str) -> bool:
    try:
        s3.head_object(Bucket=bucket, Key=key)
        return True
    except Exception:
        return False


def upload_bytes_to_s3(data: bytes, key: str, content_type: str = "image/jpeg", metadata=None):
    extra = {
        "ContentType": content_type,
        "CacheControl": "public, max-age=31536000",
    }
    if metadata:
        extra["Metadata"] = metadata
    s3.put_object(Bucket=S3_BUCKET, Key=key, Body=data, **extra)


def create_thumbnail(image_path: str) -> bytes:
    with Image.open(image_path) as img:
        img = img.convert("RGB")
        img.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT))
        canvas = Image.new("RGB", (THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), (255, 255, 255))
        x = (THUMBNAIL_WIDTH - img.width) // 2
        y = (THUMBNAIL_HEIGHT - img.height) // 2
        canvas.paste(img, (x, y))
        buf = io.BytesIO()
        canvas.save(buf, format="JPEG", quality=85, optimize=True)
        return buf.getvalue()


def capture_with_chrome(url: str, out_path: str):
    from selenium import webdriver
    from selenium.webdriver.chrome.options import Options
    from selenium.webdriver.chrome.service import Service

    options = Options()
    options.binary_location = CHROME_BIN
    options.add_argument("--headless=new")
    options.add_argument("--disable-gpu")
    options.add_argument("--no-sandbox")
    options.add_argument("--disable-dev-shm-usage")
    options.add_argument("--hide-scrollbars")
    options.add_argument("--window-size={},{}".format(SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
    options.add_argument("--ignore-certificate-errors")
    options.page_load_strategy = "normal"

    service = Service(CHROMEDRIVER_BIN)
    driver = webdriver.Chrome(service=service, options=options)
    try:
        driver.set_page_load_timeout(PAGE_LOAD_TIMEOUT)
        driver.implicitly_wait(IMPLICIT_WAIT)
        driver.get(url)
        time.sleep(2)
        total_height = driver.execute_script(
            "return Math.max(document.body.scrollHeight, document.documentElement.scrollHeight,"
            "document.body.offsetHeight, document.documentElement.offsetHeight,"
            "document.body.clientHeight, document.documentElement.clientHeight);"
        )
        final_height = max(SCREENSHOT_HEIGHT, min(int(total_height), 4000))
        driver.set_window_size(SCREENSHOT_WIDTH, final_height)
        time.sleep(1)
        driver.save_screenshot(out_path)
    finally:
        driver.quit()


def capture_with_phantomjs(url: str, out_path: str):
    script = f"""
var page = require('webpage').create();
page.settings.resourceTimeout = {PAGE_LOAD_TIMEOUT * 1000};
page.viewportSize = {{ width: {SCREENSHOT_WIDTH}, height: {SCREENSHOT_HEIGHT} }};
page.open('{url}', function(status) {{
  if (status !== 'success') {{
    phantom.exit(1);
  }} else {{
    window.setTimeout(function() {{
      page.render('{out_path}');
      phantom.exit(0);
    }}, 2000);
  }}
}});
"""
    script_path = f"/tmp/{uuid.uuid4().hex}.js"
    with open(script_path, "w", encoding="utf-8") as f:
        f.write(script)
    try:
        result = subprocess.run([PHANTOMJS_BIN, script_path], capture_output=True, timeout=PAGE_LOAD_TIMEOUT + 10)
        if result.returncode != 0:
            raise RuntimeError(result.stderr.decode("utf-8", errors="ignore") or "PhantomJS failed")
    finally:
        try:
            os.remove(script_path)
        except OSError:
            pass


def capture_screenshot(url: str, out_path: str):
    if BROWSER_ENGINE == "phantomjs":
        capture_with_phantomjs(url, out_path)
    else:
        capture_with_chrome(url, out_path)


def process_url(url: str):
    if not S3_BUCKET:
        raise RuntimeError("S3_BUCKET is not configured")

    url = validate_url(url)
    key = make_key(url)

    if object_exists(S3_BUCKET, key):
        return {
            "url": url,
            "s3_key": key,
            "image_url": s3_url_for_key(key),
            "cached": True,
        }

    tmp_path = f"/tmp/{uuid.uuid4().hex}.png"
    try:
        capture_screenshot(url, tmp_path)
        thumbnail_bytes = create_thumbnail(tmp_path)
        upload_bytes_to_s3(
            thumbnail_bytes,
            key,
            content_type="image/jpeg",
            metadata={"source-url-sha256": hashlib.sha256(url.encode()).hexdigest()},
        )
        return {
            "url": url,
            "s3_key": key,
            "image_url": s3_url_for_key(key),
            "cached": False,
        }
    finally:
        try:
            os.remove(tmp_path)
        except OSError:
            pass


@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})


@app.route("/screenshot", methods=["POST"])
def screenshot():
    try:
        payload = request.get_json(silent=True) or {}
        url = payload.get("url") or request.form.get("url") or request.args.get("url")
        result = process_url(url)
        return jsonify(result), 200
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.exception("Failed to process screenshot")
        return jsonify({"error": "internal_error", "message": str(e)}), 500


@app.route("/screenshot/preview", methods=["GET"])
def screenshot_preview():
    try:
        url = request.args.get("url")
        url = validate_url(url)
        tmp_path = f"/tmp/{uuid.uuid4().hex}.png"
        capture_screenshot(url, tmp_path)
        thumbnail_bytes = create_thumbnail(tmp_path)
        try:
            os.remove(tmp_path)
        except OSError:
            pass
        return send_file(io.BytesIO(thumbnail_bytes), mimetype="image/jpeg")
    except ValueError as e:
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        logger.exception("Preview generation failed")
        return jsonify({"error": "internal_error", "message": str(e)}), 500


